Role: {{ $('Lookup JD from Google Sheets1').item.json.jd_title }}
Candidate Score: {{ $json.composite_score }}/100
Fit Tier: {{ $json.fit_tier }}

Score Breakdown:
- Skills Score: {{ $json.score_breakdown.skills_score }}/100 (weight: 50%)
- Experience Score: {{ $json.score_breakdown.experience_score }}/100 (weight: 30%)
- Education Score: {{ $json.score_breakdown.education_score }}/100 (weight: 20%)

Matched Required Skills: {{ JSON.stringify($json.matched_required_skills) }}
Missing Required Skills: {{ JSON.stringify($json.missing_required_skills) }}
Matched Preferred Skills: {{ JSON.stringify($json.matched_preferred_skills) }}
Years Experience: {{ $json.years_experience }} (Role requires: {{ $('Lookup JD from Google Sheets1').item.json.min_years }} min, {{ $('Lookup JD from Google Sheets1').item.json.preferred_years }} preferred)
Education Level: {{ $json.education_level_detected }} (Required: {{ $('Lookup JD from Google Sheets1').item.json.required_education }})
Certifications: {{ JSON.stringify($json.certifications) }}
