// Merge explanation into candidate record
const agentOut = $input.item.json;
const prev     = $('Scoring Engine (Weighted)1').item.json;

let explanation = {};
try {
  const raw     = agentOut.output || agentOut.text || '{}';
  const cleaned = raw.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
  explanation   = JSON.parse(cleaned);
} catch(e) {
  explanation = {
    overall_summary:          'Explanation unavailable.',
    strengths:                prev.matched_required_skills || [],
    gaps:                     prev.missing_required_skills || [],
    missing_skills_assessment:'',
    experience_assessment:    '',
    education_assessment:     '',
    recommendation:           'Manual review recommended.',
    red_flags:                []
  };
}

return { json: { ...prev, explanation } };

