// Build the final complete candidate record
const agentOut = $input.item.json;
const prev     = $('Attach Explanation to Record1').item.json;

let questions = {};
try {
  const raw     = agentOut.output || agentOut.text || '{}';
  const cleaned = raw.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
  questions     = JSON.parse(cleaned);
} catch(e) {
  questions = { technical_questions: [], behavioral_questions: [], scenario_questions: [], gap_probing_questions: [] };
}

return {
  json: {
    application_id:           prev.application_id,
    applicant_email:          prev.applicant_email,
    role_id:                  prev.role_id,
    jd_title:                 prev.jd_title,
    submitted_at:             prev.submitted_at,
    source_channel:           prev.source_channel,
    gmail_message_id:         prev.gmail_message_id,
    cv_filename:              prev.cv_filename,
    cv_quality:               prev.cv_quality,
    composite_score:          prev.composite_score,
    fit_tier:                 prev.fit_tier,
    score_breakdown:          prev.score_breakdown,
    skills:                   prev.skills,
    all_candidate_skills:     prev.all_candidate_skills,
    matched_required_skills:  prev.matched_required_skills,
    missing_required_skills:  prev.missing_required_skills,
    matched_preferred_skills: prev.matched_preferred_skills,
    years_experience:         prev.years_experience,
    education_level_detected: prev.education_level_detected,
    certifications:           prev.certifications,
    notable_achievements:     prev.notable_achievements,
    jd_required_skills:       prev.jd_required_skills,
    jd_preferred_skills:      prev.jd_preferred_skills,
    jd_responsibilities:      prev.jd_responsibilities,
    explanation:              prev.explanation,
    interview_questions:      questions,
    processing_status:        'scored',
    processed_at:             new Date().toISOString()
  }
};

const d = $input.item.json;

// AI Agent returns questions as a JSON string inside .output — must parse it first
let iq = {};
try {
  const raw = $('AI Agent — Generate Interview Questions1').item.json.output || '';
  // Strip markdown fences if present
  const cleaned = raw.replace(/```json|```/gi, '').trim();
  const start = cleaned.indexOf('{');
  const end   = cleaned.lastIndexOf('}');
  if (start !== -1 && end !== -1) {
    iq = JSON.parse(cleaned.slice(start, end + 1));
  }
} catch(e) {
  iq = {};
}

const technical  = iq.technical_questions      || [];
const behavioral = iq.behavioral_questions     || [];
const gapProbing = iq.gap_probing_questions    || [];
const scenario   = iq.scenario_questions       || [];

const questionsText = [
  ...technical.map((q, i)  => `T${i+1}: ${q.question || q}`),
  ...behavioral.map((q, i) => `B${i+1}: ${q.question || q}`),
  ...gapProbing.map((q, i) => `GP${i+1}: ${q.question || q}${q.missing_skill ? ' [' + q.missing_skill + ']' : ''}`),
  ...scenario.map((q, i)   => `S${i+1}: ${q.question || q}`)
].join('\n');

return {
  json: {
    ...d,
    questions_text_preview: questionsText || 'No interview questions generated'
  }
};

const d = $input.item.json;

return {
  json: {
    ...d,
    interview_questions: null,
    rejection_reason: `Score too low for interview (${d.composite_score}/100 — ${d.fit_tier}). Minimum threshold: 50.`,
    rejected_at: new Date().toISOString()
  }
};
